module serial2parallel(
    input clk, input rst_n, input din_serial, input din_valid,
    output reg [7:0] dout_parallel, output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] temp_data;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0000;
            temp_data <= 8'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end else begin
            if (din_valid) begin
                temp_data <= {temp_data[6:0], din_serial};
                cnt <= cnt + 4'b0001;
                if (cnt == 4'b1000) begin
                    dout_parallel <= temp_data;
                    dout_valid <= 1'b1;
                end else begin
                    dout_valid <= 1'b0;
                end
            end else begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule

module div_8bit (
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

reg [7:0] dividend_reg;
reg [7:0] divisor_reg;
reg [15:0] sr; 
reg [3:0] cnt; 
reg start_cnt; 
wire [7:0] abs_divisor;
wire [7:0] abs_dividend;
wire [7:0] neg_abs_divisor;
wire [7:0] subtract_result;
wire carry_out;

assign abs_divisor = (sign && (divisor[7])) ? ~divisor + 1 : divisor;
assign abs_dividend = (sign && (dividend[7])) ? ~dividend + 1 : dividend;
assign neg_abs_divisor = ~abs_divisor + 1;
assign subtract_result = sr[15:8] - abs_divisor;
assign carry_out = subtract_result[7];

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        dividend_reg <= 8'b0;
        divisor_reg <= 8'b0;
        sr <= 16'b0;
        cnt <= 4'b0;
        start_cnt <= 1'b0;
        res_valid <= 1'b0;
    end else begin
        if (opn_valid && !res_valid) begin
            dividend_reg <= dividend;
            divisor_reg <= divisor;
            sr <= {abs_dividend, 8'b0};
            cnt <= 4'b1;
            start_cnt <= 1'b1;
            res_valid <= 1'b0;
        end else if (start_cnt) begin
            if (cnt == 4'b1000) begin
                cnt <= 4'b0;
                start_cnt <= 1'b0;
                sr <= {sr[14:0], carry_out};
                res_valid <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                sr <= {sr[14:0], carry_out};
            end
        end else if (res_valid && res_ready) begin
            res_valid <= 1'b0;
        end
    end
end

always @(*) begin
    if (rst) begin
        result = 16'b0;
    end else if (cnt == 4'b1000) begin
        result = {sr[15:8], sr[7:0]};
    end else begin
        result = 16'b0;
    end
end
endmodule

module width_8to16(
    input clk, input rst_n, input valid_in, input [7:0] data_in,
    output reg valid_out, output reg [15:0] data_out
); 
    reg [7:0] data_lock;
    reg flag;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            data_out <= 16'd0;
            valid_out <= 1'b0;
            flag <= 1'b0;
        end
        else begin
            if(valid_in && !flag) begin
                data_lock <= data_in;
                flag <= 1'b1;
            end
            else if(valid_in && flag) begin
                data_out <= {data_lock, data_in};
                valid_out <= 1'b1;
                flag <= 1'b0;
            end
        end
    end

endmodule

