module multi_16bit(
    input clk, input rst_n, input start, input [15:0] ain, input [15:0] bin,
    output [31:0] yout, output done
); 
    reg [31:0] yout_r;
    reg [15:0] areg, breg;
    reg [4:0] i;
    reg done_r;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i <= 5'd0;
        end
        else begin
            if(start && i < 5'd17) begin
                i <= i + 1;
            end
            else begin
                i <= 5'd0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 1'b0;
        end
        else begin
            if(i == 5'd16) begin
                done_r <= 1'b1;
            end
            else if(i == 5'd17) begin
                done_r <= 1'b0;
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end
        else begin
            if(start) begin
                if(i == 5'd0) begin
                    areg <= ain;
                    breg <= bin;
                end
                else if(i > 5'd0 && i < 5'd17) begin
                    if(areg[i-1]) begin
                        yout_r <= yout_r + (breg << (i-1));
                    end
                end
            end
        end
    end

    assign yout = yout_r;
    assign done = done_r;
endmodule

module multi_pipe_8bit(
    input clk, input rst_n, input mul_en_in,
    input [7:0] mul_a, input [7:0] mul_b,
    output mul_en_out, output [15:0] mul_out
);

    reg mul_en_out_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) mul_en_out_reg <= 1'b0;
        else mul_en_out_reg <= mul_en_in;
    end
    assign mul_en_out = mul_en_out_reg;

    reg [7:0] mul_a_reg, mul_b_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
        end
        else if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    wire [15:0] temp [7:0];
    assign temp[0] = mul_b_reg[0] ? {8'b0, mul_a_reg} : 16'b0;
    assign temp[1] = mul_b_reg[1] ? {7'b0, mul_a_reg, 1'b0} : 16'b0;
    assign temp[2] = mul_b_reg[2] ? {6'b0, mul_a_reg, 2'b0} : 16'b0;
    assign temp[3] = mul_b_reg[3] ? {5'b0, mul_a_reg, 3'b0} : 16'b0;
    assign temp[4] = mul_b_reg[4] ? {4'b0, mul_a_reg, 4'b0} : 16'b0;
    assign temp[5] = mul_b_reg[5] ? {3'b0, mul_a_reg, 5'b0} : 16'b0;
    assign temp[6] = mul_b_reg[6] ? {2'b0, mul_a_reg, 6'b0} : 16'b0;
    assign temp[7] = mul_b_reg[7] ? {1'b0, mul_a_reg, 7'b0} : 16'b0;

    reg [15:0] sum [7:0];
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum[0] <= 16'b0;
            sum[1] <= 16'b0;
            sum[2] <= 16'b0;
            sum[3] <= 16'b0;
            sum[4] <= 16'b0;
            sum[5] <= 16'b0;
            sum[6] <= 16'b0;
            sum[7] <= 16'b0;
        end
        else if (mul_en_out_reg) begin
            sum[0] <= temp[0];
            sum[1] <= temp[1] + temp[2];
            sum[2] <= temp[3] + temp[4];
            sum[3] <= temp[5] + temp[6];
            sum[4] <= temp[7];
            sum[5] <= 16'b0;
            sum[6] <= 16'b0;
            sum[7] <= 16'b0;
        end
    end

    assign mul_out = sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
endmodule

