module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] remainder;
    reg [4:0] i;

    always @(*) begin
        dividend = A;
        divisor = B;
        remainder = 0;
        result = 0;
        i = 16;

        while (i > 0) begin
            remainder = {remainder[14:0], dividend[15]};
            dividend = {dividend[14:0], 1'b0};

            if (remainder >= divisor) begin
                remainder = remainder - divisor;
                dividend[0] = 1'b1;
            end else begin
                dividend[0] = 1'b0;
            end

            i = i - 1;
        end

        odd = remainder;
        result = dividend;
    end

endmodule

module multi_8bit(
    input [7:0] A, B,
    output reg [15:0] product
);
    integer i;
    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    reg [15:0] partial_product;

    always @(*) begin
        multiplicand = A;
        multiplier = B;
        partial_product = 16'b0;

        for(i = 0; i < 8; i = i + 1) begin
            if(multiplier[i]) begin
                partial_product = partial_product + (multiplicand << i);
            end
        end

        product = partial_product;
    end
endmodule

module fsm (
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

    reg [2:0] state;
    reg [2:0] next_state;

    parameter S0 = 3'b000;
    parameter S1 = 3'b001;
    parameter S2 = 3'b010;
    parameter S3 = 3'b011;
    parameter S4 = 3'b100;

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            state <= S0;
            MATCH <= 1'b0;
        end
        else begin
            state <= next_state;
            case (state)
                S0: begin
                    if (IN) begin
                        next_state <= S1;
                        MATCH <= 1'b0;
                    end
                    else begin
                        next_state <= S0;
                        MATCH <= 1'b0;
                    end
                end
                S1: begin
                    if (IN) begin
                        next_state <= S1;
                        MATCH <= 1'b0;
                    end
                    else begin
                        next_state <= S2;
                        MATCH <= 1'b0;
                    end
                end
                S2: begin
                    if (IN) begin
                        next_state <= S3;
                        MATCH <= 1'b0;
                    end
                    else begin
                        next_state <= S0;
                        MATCH <= 1'b0;
                    end
                end
                S3: begin
                    if (IN) begin
                        next_state <= S4;
                        MATCH <= 1'b0;
                    end
                    else begin
                        next_state <= S2;
                        MATCH <= 1'b0;
                    end
                end
                S4: begin
                    if (IN) begin
                        next_state <= S1;
                        MATCH <= 1'b0;
                    end
                    else begin
                        next_state <= S2;
                        MATCH <= 1'b1; 
                    end
                end
                default: begin
                    next_state <= S0;
                    MATCH <= 1'b0;
                end
        endcase
    end
end // Auto-repaired
