module alu(
    input [31:0] a, b,
    input [5:0] aluc,
    output [31:0] r,
    output zero, carry, negative, overflow, flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;

    wire [31:0] a_signed, b_signed;
    wire [31:0] res;
    assign a_signed = $signed(a);
    assign b_signed = $signed(b);
    assign r[31:0] = res[31:0];
    assign flag = (aluc == SLT || aluc == SLTU) ? 1 : 1'bz;
    assign zero = ~|r ? 1 : 0;
    always @(*) begin
        case(aluc)
            ADD: res = a + b;
            ADDU: res = a + b;
            SUB: res = a - b;
            SUBU: res = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = {31'b0, a_signed < b_signed};
            SLTU: res = {31'b0, a < b};
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b >>> a[4:0];
            LUI: res = {a[15:0], 16'b0};
            default: res = 32'bz;
    endcase
end // Auto-repaired
endmodule

module edge_detect(
    input clk, input rst_n, input a,
    output reg rise, output reg down
); 
    reg prev_a;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            prev_a <= 0;
            rise <= 0;
            down <= 0;
        end else begin
            prev_a <= a;
            if (a && !prev_a) begin
                rise <= 1;
                down <= 0;
            end else if (!a && prev_a) begin
                rise <= 0;
                down <= 1;
            end else begin
                rise <= 0;
                down <= 0;
            end
        end
    end

endmodule

module adder_16bit (
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

    wire [7:0] sum_low;
    wire [7:0] sum_high;
    wire carry_out_low;
    wire carry_out_high;

    wire [8:0] adder_low_out;
    assign adder_low_out = {1'b0, a[7:0]} + {1'b0, b[7:0]} + Cin;
    assign sum_low = adder_low_out[7:0];
    assign carry_out_low = adder_low_out[8];

    wire [8:0] adder_high_out;
    assign adder_high_out = {1'b0, a[15:8]} + {1'b0, b[15:8]} + carry_out_low;
    assign sum_high = adder_high_out[7:0];
    assign carry_out_high = adder_high_out[8];

    assign y = {sum_high, sum_low};
    assign Co = carry_out_high;

endmodule

